import { createWorkflow, createAgent } from 'mastra';
import { z } from 'zod';

const codingAgent = createAgent({
  name: 'coding-assistant',
  model: 'gpt-4o',
  instructions: `You are a senior software engineer. Analyze code, fix bugs, write tests.`
});

const codeGenWorkflow = createWorkflow({
  name: 'code-debug-workflow',
  steps: [
    {
      name: 'analyze',
      agent: codingAgent,
      inputSchema: z.object({
        repoContext: z.string(),
        bugDescription: z.string()
      }),
      outputSchema: z.object({
        diagnosis: z.string(),
        proposedFix: z.string()
      })
    },
    {
      name: 'execute',
      tool: 'sandboxExecutor',
      inputSchema: z.object({ code: z.string() })
    }
  ]
});

export default codeGenWorkflow;

import { KnowledgeBase } from 'mastra/knowledge';

const repoKB = new KnowledgeBase({
  name: 'code-repo',
  sources: [
    {
      type: 'git',
      url: 'https://github.com/user/project',
      branch: 'main',
      filePatterns: ['**/*.ts', '**/*.js', 'tests/**/*.test.ts']
    }
  ],
  embeddingModel: 'text-embedding-3-small',
  chunkSize: 2000,
  chunkOverlap: 200
});

const retrieveContext = async (query: string) => {
  const results = await repoKB.search({
    query,
    limit: 10,
    filter: { metadata: { commitAfter: '2024-01-01' } }
  });
  return results.map(r => r.content).join('\n');
};

import { createTool } from 'mastra/tools';

const sandboxExecutor = createTool({
  name: 'sandbox_execute',
  description: 'Execute code in secure sandbox and return results',
  parameters: z.object({
    language: z.enum(['typescript', 'python']),
    code: z.string(),
    tests: z.string().optional()
  }),
  execute: async ({ language, code, tests }) => {
    const dockerRun = `docker run --rm -i code-sandbox-${language} 'node -e "${code}"'`;
    const result = await execShell(dockerRun);

    if (tests) {
      const testResult = await execShell(`docker run --rm -i code-sandbox-${language} 'npm test -- ${tests}'`);
      return { execution: result, tests: testResult, passed: testResult.includes('PASS') };
    }

    return { execution: result, passed: true };
  }
});

const debugWorkflow = createWorkflow({
  name: 'iterative-debug',
  steps: [
    {
      name: 'generate-fix',
      agent: codingAgent,
      inputSchema: z.object({
        prevError: z.string(),
        code: z.string()
      })
    },
    {
      name: 'validate',
      condition: async (ctx) => {
        const execResult = await sandboxExecutor(ctx);
        return !execResult.passed;
      },
      maxIterations: 5
    }
  ],
  onComplete: (ctx) => {
    if (ctx.testsPassed) {
      return { status: 'success', finalCode: ctx.code };
    }
    return { status: 'failed', attempts: ctx.iteration };
  }
});

