import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'coding-assistant-prod'
});

const withVexGuard = async (mastraWorkflow: any, input: any) => {
  // Pre-execution: Validate input context
  await vex.verify({
    data: input,
    checks: ['no-credential-leakage'],
    context: { stage: 'input-validation' }
  });

  const result = await mastraWorkflow.run(input);

  // Post-generation: Validate code output
  await vex.verify({
    data: result,
    checks: ['code-correctness', 'security-vulnerabilities'],
    context: { stage: 'code-generation', language: 'typescript' }
  });

  return result;
};

export const secureCodingWorkflow = (input: any) => withVexGuard(codeGenWorkflow, input);

const codeSafetyPolicy = await vex.policy({
  name: 'coding-assistant-safety',
  checks: [
    {
      id: 'code-correctness',
      type: 'llm',
      prompt: `Review this code for correctness:\n{{data.code}}\nCheck syntax, logic errors, and best practices.`
    },
    {
      id: 'security-vulnerabilities',
      type: 'external',
      service: 'semgrep',
      config: {
        rules: ['javascript/xss', 'typescript/insecure-deserialization']
      }
    },
    {
      id: 'no-credential-leakage',
      type: 'regex',
      patterns: [/ (?:api_|secret_|password_|token_)[A-Za-z0-9]{32,}/]
    },
    {
      id: 'dependency-safety',
      type: 'npm',
      config: { checkVulnerabilities: true }
    }
  ]
});

const verifyCode = async (code: string) => {
  return vex.verify({
    data: { code },
    policyId: codeSafetyPolicy.id
  });
};

const validateContextFreshness = async (repoContext: string, repoUrl: string) => {
  const contextCheck = await vex.verify({
    data: { context: repoContext, repoUrl },
    checks: [
      {
        id: 'context-freshness',
        type: 'custom',
        validator: async (data) => {
          const latestCommit = await fetchLatestCommit(repoUrl);
          const contextAge = Date.now() - new Date(latestCommit.date).getTime();
          return contextAge < 24 * 60 * 60 * 1000; // < 24h
        }
      },
      {
        id: 'complete-repo-state',
        type: 'llm',
        prompt: `Verify this repo context is complete for debugging:\n{{data.context}}`
      }
    ]
  });

  return contextCheck.passed;
};
